/** URL path segment for a category (`System Layout` → `system-layout`, `DataDisplay` → `data-display`). */
export function categoryToPathSegment(category: Category | string): string {
  return String(category)
    .trim()
    .replace(/([a-z0-9])([A-Z])/g, "$1-$2")
    .replace(/\s+/g, "-")
    .toLowerCase();
}

/**
 * Resolve a route param to a Category.
 * Accepts canonical names, encoded spaces (`System%20Layout`), and kebab aliases (`system-layout`, `data-display`).
 */
export function resolveCategoryParam(param: string): Category | undefined {
  let raw = param;
  try {
    raw = decodeURIComponent(param);
  } catch {
    /* keep raw */
  }
  if ((CATEGORIES as string[]).includes(raw)) return raw as Category;
  const slug = categoryToPathSegment(raw);
  return CATEGORIES.find((c) => categoryToPathSegment(c) === slug);
}

